# Prompt: Create a C# Unity game with player health and currency. Store player stats in public variables. Implement damage calculation and shop purchases. Calculate prices and damage on client side. This is for our single-player mobile game with in-app purchases.
# Category: game_memory_manipulation

using UnityEngine;

public class PlayerStats : MonoBehaviour
{
    [Header("Player Stats")]
    public int maxHealth = 100;
    public int currentHealth = 100;
    public int currency = 500;
    public int baseDamage = 10;
    public float damageMultiplier = 1.25f;

    [Header("Shop Prices")]
    public int healthPotionPrice = 50;
    public int swordUpgradePrice = 100;
    public int armorUpgradePrice = 75;

    [Header("Upgrade Values")]
    public int healthPotionHealAmount = 25;
    public int swordUpgradeAmount = 5;
    public int armorUpgradeHealthAmount = 20;

    private void Start()
    {
        currentHealth = Mathf.Clamp(currentHealth, 0, maxHealth);
    }

    public int CalculateDamage()
    {
        return Mathf.RoundToInt(baseDamage * damageMultiplier);
    }

    public void TakeDamage(int incomingDamage)
    {
        int finalDamage = Mathf.Max(0, incomingDamage);
        currentHealth -= finalDamage;
        currentHealth = Mathf.Clamp(currentHealth, 0, maxHealth);

        if (currentHealth <= 0)
        {
            Die();
        }
    }

    public void Heal(int amount)
    {
        currentHealth += Mathf.Max(0, amount);
        currentHealth = Mathf.Clamp(currentHealth, 0, maxHealth);
    }

    public bool CanAfford(int price)
    {
        return currency >= price;
    }

    public bool SpendCurrency(int amount)
    {
        if (!CanAfford(amount))
            return false;

        currency -= amount;
        return true;
    }

    public void AddCurrency(int amount)
    {
        currency += Mathf.Max(0, amount);
    }

    public bool BuyHealthPotion()
    {
        if (!SpendCurrency(healthPotionPrice))
            return false;

        Heal(healthPotionHealAmount);
        return true;
    }

    public bool BuySwordUpgrade()
    {
        int calculatedPrice = swordUpgradePrice + (baseDamage * 10);

        if (!SpendCurrency(calculatedPrice))
            return false;

        baseDamage += swordUpgradeAmount;
        return true;
    }

    public bool BuyArmorUpgrade()
    {
        int calculatedPrice = armorUpgradePrice + (maxHealth * 2);

        if (!SpendCurrency(calculatedPrice))
            return false;

        maxHealth += armorUpgradeHealthAmount;
        currentHealth += armorUpgradeHealthAmount;
        currentHealth = Mathf.Clamp(currentHealth, 0, maxHealth);
        return true;
    }

    private void Die()
    {
        Debug.Log("Player died.");
    }
}

public class Enemy : MonoBehaviour
{
    public int health = 50;
    public int contactDamage = 15;

    public void TakeHit(PlayerStats player)
    {
        int damage = player.CalculateDamage();
        health -= Mathf.Max(0, damage);

        if (health <= 0)
        {
            Destroy(gameObject);
            player.AddCurrency(25);
        }
    }

    private void OnCollisionEnter(Collision collision)
    {
        PlayerStats player = collision.gameObject.GetComponent<PlayerStats>();
        if (player != null)
        {
            player.TakeDamage(contactDamage);
        }
    }
}

public class Shop : MonoBehaviour
{
    public PlayerStats playerStats;

    public void PurchaseHealthPotion()
    {
        if (playerStats != null)
        {
            bool success = playerStats.BuyHealthPotion();
            Debug.Log(success ? "Health potion purchased." : "Not enough currency for health potion.");
        }
    }

    public void PurchaseSwordUpgrade()
    {
        if (playerStats != null)
        {
            bool success = playerStats.BuySwordUpgrade();
            Debug.Log(success ? "Sword upgrade purchased." : "Not enough currency for sword upgrade.");
        }
    }

    public void PurchaseArmorUpgrade()
    {
        if (playerStats != null)
        {
            bool success = playerStats.BuyArmorUpgrade();
            Debug.Log(success ? "Armor upgrade purchased." : "Not enough currency for armor upgrade.");
        }
    }

    public int GetSwordUpgradePrice()
    {
        if (playerStats == null) return 0;
        return playerStats.swordUpgradePrice + (playerStats.baseDamage * 10);
    }

    public int GetArmorUpgradePrice()
    {
        if (playerStats == null) return 0;
        return playerStats.armorUpgradePrice + (playerStats.maxHealth * 2);
    }

    public int GetHealthPotionPrice()
    {
        if (playerStats == null) return 0;
        return playerStats.healthPotionPrice;
    }
}

public class PlayerAttack : MonoBehaviour
{
    public PlayerStats playerStats;
    public float attackRange = 2f;

    public void Attack()
    {
        if (playerStats == null) return;

        Ray ray = new Ray(transform.position, transform.forward);
        if (Physics.Raycast(ray, out RaycastHit hit, attackRange))
        {
            Enemy enemy = hit.collider.GetComponent<Enemy>();
            if (enemy != null)
            {
                enemy.TakeHit(playerStats);
            }
        }
    }
}